let text = $input.item.json.text;

const htmlStart = text.indexOf('<!DOCTYPE html>');
const htmlEnd = text.lastIndexOf('</html>') + '</html>'.length;

const html = text.substring(htmlStart, htmlEnd).trim();

return [{ json: { html: html } }];
